Here's how to test `DataFetcher` with modern MSTest patterns:

```csharp
[TestClass]
public sealed class DataFetcherTests
{
    private readonly TestContext _testContext;

    public DataFetcherTests(TestContext testContext)
    {
        _testContext = testContext;
    }

    [TestMethod]
    [Timeout(5000)]
    public async Task FetchAsync_SuccessResponse_ReturnsContent()
    {
        // Arrange
        var handler = new FakeHttpMessageHandler("hello world", HttpStatusCode.OK);
        using var client = new HttpClient(handler);
        var fetcher = new DataFetcher(client);

        // Act
        var result = await fetcher.FetchAsync(
            "https://example.com/data", _testContext.CancellationToken);

        // Assert
        Assert.AreEqual("hello world", result);
    }

    [TestMethod]
    [Timeout(5000)]
    public async Task FetchAsync_NotFound_ThrowsHttpRequestException()
    {
        // Arrange
        var handler = new FakeHttpMessageHandler("", HttpStatusCode.NotFound);
        using var client = new HttpClient(handler);
        var fetcher = new DataFetcher(client);

        // Act & Assert
        await Assert.ThrowsExactlyAsync<HttpRequestException>(
            async () => await fetcher.FetchAsync(
                "https://example.com/missing", _testContext.CancellationToken));
    }

    [TestMethod]
    [Timeout(3000)]
    public async Task FetchAsync_CancellationRequested_ThrowsOperationCanceled()
    {
        // Arrange
        var handler = new FakeHttpMessageHandler("data", HttpStatusCode.OK, delay: TimeSpan.FromSeconds(10));
        using var client = new HttpClient(handler);
        var fetcher = new DataFetcher(client);
        using var cts = new CancellationTokenSource();
        cts.Cancel(); // cancel immediately

        // Act & Assert
        await Assert.ThrowsExactlyAsync<TaskCanceledException>(
            async () => await fetcher.FetchAsync("https://example.com", cts.Token));
    }

    // Minimal fake handler — no mocking framework needed
    private sealed class FakeHttpMessageHandler : HttpMessageHandler
    {
        private readonly string _content;
        private readonly HttpStatusCode _statusCode;
        private readonly TimeSpan _delay;

        public FakeHttpMessageHandler(
            string content, HttpStatusCode statusCode, TimeSpan delay = default)
        {
            _content = content;
            _statusCode = statusCode;
            _delay = delay;
        }

        protected override async Task<HttpResponseMessage> SendAsync(
            HttpRequestMessage request, CancellationToken cancellationToken)
        {
            if (_delay > TimeSpan.Zero)
                await Task.Delay(_delay, cancellationToken);

            return new HttpResponseMessage(_statusCode)
            {
                Content = new StringContent(_content),
            };
        }
    }
}
```

**Key patterns demonstrated:**

| Pattern | How |
|---|---|
| **Async tests** | Return `Task`, use `async`/`await` — MSTest natively awaits them |
| **Timeouts** | `[Timeout(ms)]` auto-cancels `TestContext.CancellationToken` on expiry |
| **CancellationToken** | Pass `_testContext.CancellationToken` so `[Timeout]` can actually stop the test |
| **Cancellation testing** | Create a pre-cancelled `CancellationTokenSource` and assert `TaskCanceledException` |
| **Exception testing** | `Assert.ThrowsExactlyAsync<T>` instead of `[ExpectedException]` |
| **HttpClient testing** | Custom `HttpMessageHandler` — no mocking library required |
| **Sealed class** | `sealed` on test class for performance and design clarity |
| **Constructor injection** | `TestContext` injected via constructor (MSTest 3.6+), enabling `readonly` |
